class disable_gc(contextlib.ContextDecorator):
  _depth = 0
  def __enter__(self):
    if type(self)._depth == 0:
      self._was_enabled = gc.isenabled()
      if self._was_enabled: gc.disable()
    type(self)._depth += 1
  def __exit__(self, *exc):
    type(self)._depth -= 1
    if type(self)._depth == 0 and self._was_enabled: gc.enable()
